{
  "command": "cat > /tmp/analyze3.py << 'PYEOF'
import sqlite3
import json
import re

conn = sqlite3.connect('/Users/shreyashankar/Documents/projects/DataAgentBench/query_PATENTS/query_dataset/patent_publication.db')
cur = conn.cursor()

cur.execute("SELECT Patents_info FROM publicationinfo WHERE Patents_info LIKE '%UNIV CALIFORNIA%'")
uc_pubs = set()
for row in cur.fetchall():
    info = row[0]
    m = re.search(r'pub(?:lication)?\.?\s*(?:number|no\.?|num\.?)\s*([A-Z]{2}-[A-Z0-9]+(?:-[A-Z0-9]+)?)', info, re.IGNORECASE)
    if m:
        uc_pubs.add(m.group(1))

uc_list_upper = {p.upper() for p in uc_pubs}

cur.execute("SELECT Patents_info, citation, cpc FROM publicationinfo WHERE citation IS NOT NULL AND citation != ''")
results = []
for row in cur.fetchall():
    info, cit, cpc = row
    if 'UNIV CALIFORNIA' in info:
        continue
    try:
        cits = json.loads(cit)
    except Exception:
        continue
    cite_pubs = {c.get('publication_number','').upper() for c in cits if c.get('publication_number')}
    if cite_pubs & uc_list_upper:
        results.append((info, cpc))

def extract_assignee(info):
    # Try multiple patterns
    patterns = [
        r'is\s+assigned\s+to\s+([A-Z][A-Z0-9 &\-.]+?)\s+and\s+has',
        r'is\s+owned\s+by\s+([A-Z][A-Z0-9 &\-.]+?)\s+and\s+has',
        r'is\s+held\s+by\s+([A-Z][A-Z0-9 &\-.]+?)\s+and\s+has',
        r'is\s+belonging\s+to\s+([A-Z][A-Z0-9 &\-.]+?)\s+and\s+has',
        r'^([A-Z][A-Z0-9 &\-.]+?)\s+holds\s+',
        r',\s+assigned\s+to\s+([A-Z][A-Z0-9 &\-.]+?),',
        r',\s+owned\s+by\s+([A-Z][A-Z0-9 &\-.]+?),',
        r',\s+held\s+by\s+([A-Z][A-Z0-9 &\-.]+?),',
        r',\s+belonging\s+to\s+([A-Z][A-Z0-9 &\-.]+?),',
    ]
    for p in patterns:
        m = re.search(p, info)
        if m:
            return m.group(1).strip()
    return None

def extract_primary_subclass(cpc_str):
    try:
        cpcs = json.loads(cpc_str)
    except Exception:
        return None
    # Find CPC marked first=True, else the first entry
    first = None
    for c in cpcs:
        if c.get('first'):
            first = c.get('code')
            break
    if not first and cpcs:
        first = cpcs[0].get('code')
    if not first:
        return None
    # Subclass is the first 4 characters
    m = re.match(r'^([A-Z]\d{2}[A-Z])', first)
    if m:
        return m.group(1)
    return None

for info, cpc in results:
    assignee = extract_assignee(info)
    subclass = extract_primary_subclass(cpc)
    print(f"Assignee: {assignee}")
    print(f"Primary subclass: {subclass}")
    print(f"Info: {info}")
    print("---")
PYEOF
