{
  "command": "python3 << 'EOF'
import re
from pymongo import MongoClient
import duckdb
from collections import Counter, defaultdict

client = MongoClient('mongodb://localhost:27017/')
db = client['yelp_db']

businesses = list(db.business.find({"attributes.BusinessAcceptsCreditCards": "True"}))

STATE_CODES = {
    'AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA',
    'ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK',
    'OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY','DC'
}

def strip_location(desc):
    """Strip the location preamble: 'Located at X Y, ST,' or 'Situated at ... ST,' or 'This City, ST location'"""
    # Try 1: remove up to and including ", ST," where ST is a state code
    m = re.search(r",\s*([A-Z]{2}),\s*", desc)
    if m and m.group(1) in STATE_CODES:
        return desc[m.end():]
    # Try 2: "This CITY, ST location ..."
    m = re.search(r"This .*?,\s*([A-Z]{2})\s+location\s*", desc)
    if m and m.group(1) in STATE_CODES:
        return desc[m.end():]
    # Try 3: "Located in CITY, ST," (no state code, just "in <city>, ST,")
    m = re.search(r"Located in .*?,\s*([A-Z]{2}),\s*", desc)
    if m and m.group(1) in STATE_CODES:
        return desc[m.end():]
    return desc

def is_category(s):
    if not s or len(s) > 50:
        return False
    if s[0].islower():
        return False
    if not re.match(r"^[A-Z][A-Za-z0-9'’()&/\- ]+$", s):
        return False
    lower = s.lower()
    bad_endings = ('location', 'establishment', 'facility', 'spot', 'store', 'eatery', 'place', 'venue', 'business', 'shop', 'destination', 'practice')
    for w in bad_endings:
        if lower == w or lower.endswith(' ' + w):
            return False
    return True

def extract_categories(desc):
    cleaned = strip_location(desc)
    # Now find the longest run of comma-separated category-like phrases
    tokens = re.split(r',\s*', cleaned)
    runs = []
    current = []
    for tok in tokens:
        pieces = tok.split('.')
        for idx, piece in enumerate(pieces):
            piece = piece.strip()
            # Remove leading connectors
            piece = re.sub(r"^(?:and|or|to)\s+", "", piece).strip()
            if is_category(piece):
                current.append(piece)
            else:
                # Try extracting the category from the END of the piece
                # e.g. "this eatery specializes in Vietnamese" -> "Vietnamese"
                m = re.search(r"(?:^|(?:\b(?:in|for|featuring|including|of|across|seeking|offering|enjoying|from|encompassing|such as|categories|such)\b)\s+(?:a\s+variety\s+of\s+offerings,?\s*including\s+)?['’]?)([A-Z][A-Za-z'’()&/\- ]+)$", piece)
                if m:
                    cand = m.group(1).strip()
                    if is_category(cand):
                        current.append(cand)
                        continue
                # End current run
                if current:
                    runs.append(current)
                    current = []
            if idx < len(pieces) - 1:
                # End of sentence
                if current:
                    runs.append(current)
                    current = []
    if current:
        runs.append(current)

    if not runs:
        return []
    best = max(runs, key=len)
    return best

cat_counter = Counter()
biz_to_cats = {}
for b in businesses:
    cats = extract_categories(b['description'])
    biz_to_cats[b['business_id']] = cats
    for c in cats:
        cat_counter[c] += 1
    if not cats:
        print(f"NO CATS: {b['business_id']} | {b['description']}")

print("\nTop categories:")
for c, n in cat_counter.most_common(30):
    print(f"  {n:3d}  {c}")

print("\n\nPer-business categories:")
for bid, cats in sorted(biz_to_cats.items(), key=lambda x: int(x[0].split('_')[1])):
    print(f"  {bid}: {cats}")
EOF",
  "description": "Extract categories after stripping location"
}
